import { useCallback, useEffect, useState } from 'react';
import {
  detectDateRangePreset,
  type DatePreset,
} from '@linm-soft/common-components';
import {
  getDefaultVoucherListDateRange,
  MFE_LIST_FILTER_NS,
  readListFilterSession,
  type VoucherListFilterSession,
  writeListFilterSession,
} from '../utils/listFilterSession';
import { readListFilterAuthScopeFromStorage } from '../utils/listFilterAuthScope';

function resolveInitialDatePreset(
  saved: VoucherListFilterSession | null,
  fromDate?: string,
  toDate?: string,
): DatePreset {
  if (saved?.datePreset !== undefined) return saved.datePreset;
  return detectDateRangePreset(fromDate, toDate) || 'today';
}

export function useVoucherListFilterState(listScope: string) {
  const [auth, setAuth] = useState(readListFilterAuthScopeFromStorage);
  const [initialized, setInitialized] = useState(false);

  useEffect(() => {
    const sync = () => setAuth(readListFilterAuthScopeFromStorage());
    window.addEventListener('storage', sync);
    window.addEventListener('linm:auth:logout', sync);
    return () => {
      window.removeEventListener('storage', sync);
      window.removeEventListener('linm:auth:logout', sync);
    };
  }, []);

  const [fromDate, setFromDate] = useState<string | undefined>();
  const [toDate, setToDate] = useState<string | undefined>();
  const [datePreset, setDatePreset] = useState<DatePreset>('today');
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState('');
  const [processingLevel, setProcessingLevel] = useState('');
  const [page, setPage] = useState(1);

  useEffect(() => {
    const saved = readListFilterSession<VoucherListFilterSession>(
      MFE_LIST_FILTER_NS,
      listScope,
      auth,
    );
    const initial = saved ?? {
      ...getDefaultVoucherListDateRange(),
      datePreset: 'today' as DatePreset,
      page: 1,
      search: '',
      status: '',
      processingLevel: '',
    };
    setFromDate(initial.fromDate);
    setToDate(initial.toDate);
    setDatePreset(resolveInitialDatePreset(saved, initial.fromDate, initial.toDate));
    const initialSearch = initial.search ?? '';
    setSearch(initialSearch);
    setSearchDraft(initialSearch);
    setStatus(initial.status ?? '');
    setProcessingLevel(initial.processingLevel ?? '');
    setPage(initial.page ?? 1);
    setInitialized(true);
  }, [listScope, auth]);

  useEffect(() => {
    if (!initialized) return;
    writeListFilterSession<VoucherListFilterSession>(MFE_LIST_FILTER_NS, listScope, auth, {
      fromDate,
      toDate,
      datePreset,
      search: search || undefined,
      status: status || undefined,
      processingLevel: processingLevel || undefined,
      page,
    });
  }, [initialized, listScope, auth, fromDate, toDate, datePreset, search, status, processingLevel, page]);

  const resetPage = useCallback(() => setPage(1), []);

  const applyDateRange = useCallback(
    (from?: string, to?: string, preset?: DatePreset) => {
      setFromDate(from);
      setToDate(to);
      if (preset !== undefined) setDatePreset(preset);
    },
    [],
  );

  return {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    processingLevel,
    setProcessingLevel,
    page,
    setPage,
    resetPage,
  };
}
