import { hasValidAuthToken, getAuthUser } from '@linm-soft/common-components';
import { buildListFilterAuthScope } from './listFilterSession';

/** Reads auth user when JWT envelope is valid. Standalone → anon scope. */
export function readListFilterAuthScopeFromStorage(): string {
  if (typeof localStorage === 'undefined' || !hasValidAuthToken()) {
    return buildListFilterAuthScope(undefined, undefined);
  }
  const user = getAuthUser();
  if (!user) return buildListFilterAuthScope(undefined, undefined);
  return buildListFilterAuthScope(user.id, user.companyId);
}
